package com.secman.service

import com.secman.domain.Asset
import com.secman.domain.Vulnerability
import com.secman.domain.VulnerabilityException
import com.secman.repository.AssetRepository
import com.secman.repository.VulnerabilityRepository
import com.secman.testutil.BaseIntegrationTest
import com.secman.testutil.DockerAvailable
import io.micronaut.test.extensions.junit5.annotation.MicronautTest
import io.micronaut.test.support.TestPropertyProvider
import jakarta.inject.Inject
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.condition.EnabledIf
import java.time.LocalDateTime

@MicronautTest(environments = ["test"], transactional = false)
@EnabledIf("com.secman.testutil.DockerAvailable#isDockerAvailable")
class VulnerabilityServicePreviewIntegrationTest : TestPropertyProvider {

    @Inject
    lateinit var assetRepository: AssetRepository

    @Inject
    lateinit var vulnerabilityRepository: VulnerabilityRepository

    @Inject
    lateinit var vulnerabilityService: VulnerabilityService

    override fun getProperties(): MutableMap<String, String> {
        return mutableMapOf(
            "datasources.default.url" to BaseIntegrationTest.mariadb.jdbcUrl,
            "datasources.default.username" to BaseIntegrationTest.mariadb.username,
            "datasources.default.password" to BaseIntegrationTest.mariadb.password,
            "datasources.default.driver-class-name" to "org.mariadb.jdbc.Driver"
        )
    }

    @Test
    fun `AWS account preview initializes asset data for response DTOs`() {
        val accountId = "987654321098"
        val assetName = "preview-aws-${System.nanoTime()}"
        val asset = assetRepository.save(
            Asset(
                name = assetName,
                type = "SERVER",
                owner = "preview-test",
                cloudAccountId = accountId
            )
        )
        val vulnerability = vulnerabilityRepository.save(
            Vulnerability(
                asset = asset,
                vulnerabilityId = "CVE-PREVIEW-0001",
                cvssSeverity = "High",
                scanTimestamp = LocalDateTime.now().minusDays(5)
            )
        )

        try {
            val (sample, totalCount) = vulnerabilityService.previewExceptionImpact(
                subject = VulnerabilityException.Subject.ALL_VULNS,
                scope = VulnerabilityException.Scope.AWS_ACCOUNT,
                scopeValue = accountId,
                limit = 10
            )

            assertThat(totalCount).isGreaterThanOrEqualTo(1)
            assertThat(sample).anySatisfy { row ->
                assertThat(row.id).isEqualTo(vulnerability.id)
                assertThat(row.assetId).isEqualTo(asset.id)
                assertThat(row.assetName).isEqualTo(assetName)
            }
        } finally {
            vulnerabilityRepository.deleteById(vulnerability.id!!)
            assetRepository.deleteById(asset.id!!)
        }
    }
}

